import{_ as e,o as a,c as l,a3 as o}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"FFmpeg 多媒体工作台","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/ffmpeg-tools.md","filePath":"user-guide/tools/ffmpeg-tools.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/ffmpeg-tools.md"};function i(d,t,n,s,h,p){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="ffmpeg-多媒体工作台" tabindex="-1">FFmpeg 多媒体工作台 <a class="header-anchor" href="#ffmpeg-多媒体工作台" aria-label="Permalink to &quot;FFmpeg 多媒体工作台&quot;">​</a></h1><blockquote><p>一站式音视频处理工具箱，基于 FFmpeg 引擎的强大能力，提供直观的图形化操作界面。</p></blockquote><p>FFmpeg 多媒体工作台是 AIO Hub 内置的专业音视频处理工具。它通过图形化界面将 FFmpeg 命令行工具的复杂参数转化为直观的控件，让视频压缩、格式转换、音频提取等常见任务变得简单高效。</p><h2 id="功能亮点" tabindex="-1">功能亮点 <a class="header-anchor" href="#功能亮点" aria-label="Permalink to &quot;功能亮点&quot;">​</a></h2><ul><li><strong>🎯 场景化预设</strong>：内置微信、抖音、B站、极致压缩等 8 套场景预设，一键应用即可开始处理</li><li><strong>📊 实时进度监控</strong>：毫秒级进度更新，实时显示处理速度（Speed）、码率（Bitrate）和当前时间点</li><li><strong>🔄 多任务并行</strong>：支持同时运行多个 FFmpeg 进程，任务监控面板清晰管理所有处理队列</li><li><strong>🎬 内置媒体预览</strong>：拖入文件后自动解析元数据，支持视频/音频播放预览</li><li><strong>⚡ 智能参数生成</strong>：根据你的参数配置实时生成 FFmpeg 命令行，学习 FFmpeg 的同时确保参数正确</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h3><p>该工具默认使用系统中注册的 <code>ffmpeg</code> 命令。如果尚未安装 FFmpeg，请在服务配置中设置 FFmpeg 二进制文件的实际路径。</p><ol><li>在主页中点击「FFmpeg 工具」卡片进入工作台</li><li>点击「服务配置」标签页</li><li>填写 FFmpeg 和 FFprobe 的路径（如 <code>C:\\ffmpeg\\bin\\ffmpeg.exe</code>），或确保它们已加入系统 PATH</li></ol><p>![服务配置截图]（TODO: 服务配置页面截图）</p><h3 id="第一次压缩视频" tabindex="-1">第一次压缩视频 <a class="header-anchor" href="#第一次压缩视频" aria-label="Permalink to &quot;第一次压缩视频&quot;">​</a></h3><ol><li>切换到「工作台」标签页</li><li>将视频文件拖入右侧的待处理文件区域，或点击「选择文件」按钮打开系统对话框</li><li>在「处理配置」区域，从预设下拉列表中选择「微信视频号优化」</li><li>点击底部醒目的「开始处理任务」按钮</li><li>切换至「任务监控」标签页，查看实时进度</li></ol><p>![工作台截图]（TODO: 工作台布局截图）</p><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="工作台主界面" tabindex="-1">工作台主界面 <a class="header-anchor" href="#工作台主界面" aria-label="Permalink to &quot;工作台主界面&quot;">​</a></h3><p>工作台采用左右分栏布局：</p><ul><li><strong>左侧 — 处理配置</strong>：包含预设选择、参数表单和 FFmpeg 指令预览</li><li><strong>右侧 — 文件管理</strong>：文件拖入区、媒体元数据显示和播放预览</li></ul><h4 id="处理模式" tabindex="-1">处理模式 <a class="header-anchor" href="#处理模式" aria-label="Permalink to &quot;处理模式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>典型用途</th></tr></thead><tbody><tr><td><strong>视频重编码</strong></td><td>指定视频编码器（libx264/libx265）和 CRF 或码率参数</td><td>压缩视频体积、调整画质</td></tr><tr><td><strong>音频提取</strong></td><td>移除视频轨道，仅保留音频并转码</td><td>从视频中提取背景音乐</td></tr><tr><td><strong>格式转换</strong></td><td>使用 <code>-c copy</code> 快速转换封装格式</td><td>MP4 转 MKV，无需重编码</td></tr><tr><td><strong>自定义模式</strong></td><td>直接输入原始 FFmpeg 命令行参数</td><td>高级用户自由发挥</td></tr></tbody></table><h4 id="参数调优指南" tabindex="-1">参数调优指南 <a class="header-anchor" href="#参数调优指南" aria-label="Permalink to &quot;参数调优指南&quot;">​</a></h4><p><strong>视频编码器</strong></p><ul><li><code>libx264</code>：兼容性最佳，几乎所有播放器和平台都支持</li><li><code>libx265</code>（HEVC）：同等画质下体积小 30-50%，但兼容性略差</li><li><code>h264_nvenc</code>：NVIDIA 显卡硬件编码，处理速度极快但画质稍逊</li></ul><p><strong>CRF（恒定质量因子）</strong></p><ul><li><strong>18-22</strong>：高画质（适合存档、B站投稿）</li><li><strong>23-25</strong>：平衡（日常使用）</li><li><strong>26-30</strong>：高压缩（适合网传分享）</li></ul><h3 id="任务监控" tabindex="-1">任务监控 <a class="header-anchor" href="#任务监控" aria-label="Permalink to &quot;任务监控&quot;">​</a></h3><p>「任务监控」标签页提供了完整的任务管理能力：</p><ul><li><strong>统计概览</strong>：顶部四个统计卡片分别展示总任务数、处理中、已完成和失败数量</li><li><strong>任务表格</strong>：显示每个任务的名称、状态、处理速度/码率/时间、操作按钮</li><li><strong>操作按钮</strong>： <ul><li>🔴 停止按钮：终止正在处理的任务</li><li>ℹ️ 媒体详情：查看输出文件的完整媒体信息</li><li>📂 定位文件：在文件管理器中打开输出文件所在目录</li><li>➡️ 发送到：将输出文件直接发送给 LLM Chat 或转写工具</li><li>🗑️ 删除记录：从任务列表中移除该记录</li></ul></li></ul><p>![任务监控截图]（TODO: 任务监控页面截图）</p><h3 id="预设管理" tabindex="-1">预设管理 <a class="header-anchor" href="#预设管理" aria-label="Permalink to &quot;预设管理&quot;">​</a></h3><p>系统内置 8 套预设，覆盖常见场景：</p><table tabindex="0"><thead><tr><th>预设名称</th><th>核心参数</th><th>适用场景</th></tr></thead><tbody><tr><td>微信视频号优化</td><td>libx264 + 1080p + CRF 23</td><td>微信朋友圈/视频号</td></tr><tr><td>抖音/快手上传</td><td>libx264 + 码率 4000k</td><td>短视频平台</td></tr><tr><td>极致压缩 (H.265)</td><td>libx265 + CRF 28 + 720p</td><td>存档备份，最小体积</td></tr><tr><td>高保真音频提取</td><td>AAC 320kbps</td><td>提取高质量伴奏</td></tr><tr><td>无损音频提取</td><td>FLAC 无损</td><td>音频存档</td></tr><tr><td>快速转换 (流拷贝)</td><td><code>-c copy</code> 不重编码</td><td>仅转换封装格式</td></tr><tr><td>B站投稿优化</td><td>libx264 + CRF 20 + slow</td><td>满足 B站 二压标准</td></tr><tr><td>4K HDR 保留</td><td>libx265 + CRF 22 + 10bit</td><td>高画质素材归档</td></tr></tbody></table><p>你也可以将当前参数保存为自定义预设，支持重命名、删除、导出为 JSON 文件分享给他人，或导入他人分享的预设。</p><p>打开「专业模式」开关后，参数表单会显示更多高级选项，如像素格式（pixel format）、音频声道数等。</p><h3 id="服务配置" tabindex="-1">服务配置 <a class="header-anchor" href="#服务配置" aria-label="Permalink to &quot;服务配置&quot;">​</a></h3><p>在「服务配置」标签页可以设置：</p><ul><li><strong>FFmpeg 路径</strong>：FFmpeg 可执行文件的路径</li><li><strong>FFprobe 路径</strong>：FFprobe 可执行文件的路径（用于详细媒体信息分析）</li><li><strong>默认输出目录</strong>：处理完成后文件的存放位置</li><li><strong>最大并发任务数</strong>：同时处理的 FFmpeg 进程数量，默认为 2</li></ul><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="跨工具协作" tabindex="-1">跨工具协作 <a class="header-anchor" href="#跨工具协作" aria-label="Permalink to &quot;跨工具协作&quot;">​</a></h3><p>完成任务后，在「任务监控」表格中点击已完成任务的「发送到」按钮，可以：</p><ul><li><strong>发送到 LLM Chat</strong>：将输出的音频/视频文件直接作为 LLM 对话的附件</li><li><strong>发送到转写工具</strong>：将输出的音频文件直接发送给语音转文字工具</li></ul><h3 id="预设导出与分享" tabindex="-1">预设导出与分享 <a class="header-anchor" href="#预设导出与分享" aria-label="Permalink to &quot;预设导出与分享&quot;">​</a></h3><ol><li>在工作台左侧的预设选择区域点击「管理预设」（齿轮图标）</li><li>在管理弹窗中，点击任意预设（内置或自定义）右侧的「导出」按钮</li><li>系统会下载一个 JSON 文件，其中包含该预设的完整参数快照</li><li>将 JSON 文件分享给其他人，对方点击管理弹窗底部的「导入预设」即可使用</li></ol><h3 id="配合专业模式使用" tabindex="-1">配合专业模式使用 <a class="header-anchor" href="#配合专业模式使用" aria-label="Permalink to &quot;配合专业模式使用&quot;">​</a></h3><p>开启「专业模式」后，参数表单会显示更多高级选项：</p><ul><li><strong>像素格式（pixel format）</strong>：如 <code>yuv420p</code>（通用）、<code>yuv422p</code>（高质量）、<code>yuv420p10le</code>（10bit HDR）</li><li><strong>音频采样率</strong>：如 44100（CD 音质）、48000（专业音质）</li><li><strong>音频声道数</strong>：单声道（1）或立体声（2）</li><li><strong>音频编码器</strong>：支持 <code>libmp3lame</code>（MP3）、<code>libopus</code>（Opus）、<code>copy</code>（流拷贝）等</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么处理失败" tabindex="-1">Q：为什么处理失败？ <a class="header-anchor" href="#q-为什么处理失败" aria-label="Permalink to &quot;Q：为什么处理失败？&quot;">​</a></h3><p>请按以下顺序排查：</p><ol><li>确认 FFmpeg 路径配置正确（可以在系统终端中手动运行 <code>ffmpeg -version</code> 测试）</li><li>查看「实时控制台」中的 FFmpeg 日志输出，具体错误信息会指导你定位问题</li><li>检查输入文件是否损坏或被其他程序占用</li><li>确认输出目录有写入权限且磁盘空间充足</li></ol><h3 id="q-如何实现最快速度的格式转换" tabindex="-1">Q：如何实现最快速度的格式转换？ <a class="header-anchor" href="#q-如何实现最快速度的格式转换" aria-label="Permalink to &quot;Q：如何实现最快速度的格式转换？&quot;">​</a></h3><p>选择「快速转换 (流拷贝)」预设。该模式使用 <code>-c copy</code> 参数，不重新编码音视频流，仅转换封装格式（如 MKV → MP4），速度几乎与文件 I/O 一致。</p><h3 id="q-如何得到最小的文件体积" tabindex="-1">Q：如何得到最小的文件体积？ <a class="header-anchor" href="#q-如何得到最小的文件体积" aria-label="Permalink to &quot;Q：如何得到最小的文件体积？&quot;">​</a></h3><p>选择「极致压缩 (H.265)」预设，或手动调高 CRF 值（如 30-35）并降低分辨率。注意：过度压缩会导致画质严重下降，建议先在部分片段上测试效果。</p><h3 id="q-为什么系统没有检测到-ffmpeg" tabindex="-1">Q：为什么系统没有检测到 FFmpeg？ <a class="header-anchor" href="#q-为什么系统没有检测到-ffmpeg" aria-label="Permalink to &quot;Q：为什么系统没有检测到 FFmpeg？&quot;">​</a></h3><ul><li><strong>Windows</strong>：检查系统环境变量 PATH 是否包含 FFmpeg 的 bin 目录。重启应用后生效。</li><li><strong>macOS/Linux</strong>：使用包管理器安装后通常自动注册。也可通过 <code>which ffmpeg</code> 确认安装路径，然后在服务配置中手动填写。</li></ul><h3 id="q-任务监控中的-应用重启-任务已自动取消-是什么意思" tabindex="-1">Q：任务监控中的&quot;应用重启，任务已自动取消&quot;是什么意思？ <a class="header-anchor" href="#q-任务监控中的-应用重启-任务已自动取消-是什么意思" aria-label="Permalink to &quot;Q：任务监控中的&quot;应用重启，任务已自动取消&quot;是什么意思？&quot;">​</a></h3><p>FFmpeg 进程是独立于应用运行的操作系统进程。如果 AIO Hub 意外关闭，正在执行的 FFmpeg 任务会随之终止。应用重启后，会自动将这些未完成的任务标记为「已取消」状态，避免状态不一致。你可以清除这些历史记录后重新提交任务。</p>',57)])])}const u=e(r,[["render",i]]);export{c as __pageData,u as default};
